const express = require('express');
const bodyParser = require('body-parser');
const crypto = require('crypto');

const app = express();
app.use(bodyParser.json());

// Mock database to store level completion data and rewards
let levelCompletions = [];
let rewards = [];

// Middleware to validate input
function validateInput(req, res, next) {
    const { score, time } = req.body;
    if (typeof score !== 'number' || typeof time !== 'number') {
        return res.status(400).json({ error: 'Invalid input' });
    }
    next();
}

// Middleware to prevent replay attacks
const nonceStore = new Map();

function generateNonce() {
    return crypto.randomBytes(16).toString('hex');
}

function validateNonce(req, res, next) {
    const { nonce } = req.headers;
    if (!nonce || !nonceStore.has(nonce)) {
        return res.status(403).json({ error: 'Invalid nonce' });
    }
    nonceStore.delete(nonce);
    next();
}

// Endpoint to complete a level
app.post('/complete-level', validateInput, validateNonce, (req, res) => {
    const { score, time } = req.body;
    const levelId = crypto.randomBytes(4).toString('hex'); // Simulate level ID

    levelCompletions.push({ levelId, score, time });
    res.status(201).json({ message: 'Level completed successfully' });
});

// Endpoint to claim rewards
app.post('/claim-rewards', validateInput, validateNonce, (req, res) => {
    const { score } = req.body;
    let rewardAmount = 0;

    // Award rewards based on score
    if (score > 1000) {
        rewardAmount = 5;
    } else if (score > 500) {
        rewardAmount = 3;
    } else {
        rewardAmount = 1;
    }

    rewards.push({ score, reward: rewardAmount });
    res.status(200).json({ message: 'Rewards claimed successfully', reward: rewardAmount });
});

// Middleware to generate and validate nonce
app.use((req, res, next) => {
    const nonce = generateNonce();
    req.headers['nonce'] = nonce;
    nonceStore.set(nonce, true);
    next();
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});